from dataclasses import dataclass


@dataclass
class User:
    name: str
    email: str
    age: int = 0


def make_user(name, age=0, email=None):
    # BUG: calling order swaps positional args
    # caller passes (name, 42, 'a@x.com') -> age=42, email='a@x.com'
    # but we pass (name, email, age) to User which causes conflict with kwarg email
    return User(name, email, age=age, email=email)


def fetch_defaults():
    return ('alice', 42, 'a@x.com')


def main():
    name, age, email = fetch_defaults()
    u = make_user(name, age, email)
    print(u)


if __name__ == '__main__':
    main()
